blocks.body:
{
    "level": "B2–C1",
    "intro": "W tej sekcji nauczysz się <strong>bezokolicznika strony biernej i gerunda</strong>, kluczowych konstrukcji w pisaniu akademickim i formalnym.",
    "rules": [
        {
            "label": "Bezokolicznik",
            "color": "emerald",
            "text": "<strong>to be done</strong> — czynność teraźniejsza lub przyszła:",
            "example": "The report needs to be finished."
        },
        {
            "label": "Bezokolicznik perfect",
            "color": "blue",
            "text": "<strong>to have been done</strong> — wcześniejsza czynność:",
            "example": "He seems to have been promoted."
        },
        {
            "label": "Rzeczownik odsłowny",
            "color": "rose",
            "text": "<strong>being + V3</strong> — bierna forma gerunda:",
            "example": "She hates being interrupted."
        },
        {
            "label": "Gerund perfect",
            "color": "amber",
            "text": "<strong>having been + V3</strong> — wcześniejsza czynność:",
            "example": "Having been warned, he was careful."
        }
    ]
}

{
    "title": "1. Cztery formy pasywne",
    "intro": "Porównanie form czynnych i biernych bezokolicznika i gerunda:",
    "items": [
        {
            "label": "Bezokolicznik czynny",
            "title": "to do",
            "subtitle": "→ biernie: to be done"
        },
        {
            "label": "Bezokolicznik perfect",
            "title": "to do",
            "subtitle": "→ biernie: to have been done"
        },
        {
            "label": "Gerund czynny",
            "title": "doing",
            "subtitle": "→ biernie: being done"
        },
        {
            "label": "Gerund perfect",
            "title": "having done",
            "subtitle": "→ biernie: having been done"
        }
    ]
}

{
    "title": "2. Bierny bezokolicznik",
    "sections": [
        {
            "label": "Po potrzebie/chceniu/oczekiwaniu",
            "color": "emerald",
            "description": "Kiedy ktoś chce/oczekuje <strong>coś, co zostanie zrobione</strong>:",
            "examples": [
                {
                    "en": "The report needs to be finished by Friday.",
                    "ua": "Raport musi być gotowy do piątku."
                },
                {
                    "en": "I want this issue to be resolved.",
                    "ua": "Chcę, żeby ten problem został rozwiązany."
                },
                {
                    "en": "They expect the project to be approved.",
                    "ua": "Oczekują, że projekt zostanie zatwierdzony."
                }
            ]
        },
        {
            "label": "Po seem i appear",
            "color": "blue",
            "description": "Używamy tej formy, gdy opisujemy wrażenie, pozór albo przypuszczenie:",
            "examples": [
                {
                    "en": "The door seems to be locked.",
                    "ua": "Wygląda na to, że drzwi są zamknięte."
                },
                {
                    "en": "He appears to be respected by everyone.",
                    "ua": "Wygląda na to, że wszyscy go szanują."
                }
            ]
        }
    ]
}

{
    "title": "3. Bierny bezokolicznik perfect",
    "sections": [
        {
            "label": "Wcześniejsza czynność",
            "color": "emerald",
            "description": "Wskazuje czynność, która <strong>wystąpiła wcześniej</strong>:",
            "examples": [
                {
                    "en": "He seems to have been promoted.",
                    "ua": "Wygląda na to, że dostał awans."
                },
                {
                    "en": "The documents appear to have been lost.",
                    "ua": "Wygląda na to, że dokumenty zaginęły."
                }
            ]
        },
        {
            "label": "Struktury raportowania",
            "color": "blue",
            "description": "W konstrukcjach bezosobowych z <strong>mówi się/wierzy/relacjonuje</strong>:",
            "examples": [
                {
                    "en": "He is believed to have been kidnapped.",
                    "ua": "Uważa się, że został porwany."
                },
                {
                    "en": "She is reported to have been seen in Paris.",
                    "ua": "Według doniesień widziano ją w Paryżu."
                }
            ]
        }
    ]
}

{
    "title": "4. Bierny gerund",
    "sections": [
        {
            "label": "Po czasownikach uczuć",
            "color": "emerald",
            "description": "Po czasownikach typu <strong>like, hate, enjoy, avoid</strong>, gdy podmiot doświadcza czynności:",
            "examples": [
                {
                    "en": "She hates being interrupted.",
                    "ua": "Nie lubi, gdy ktoś jej przerywa."
                },
                {
                    "en": "Nobody likes being criticized.",
                    "ua": "Nikt nie lubi być krytykowany."
                },
                {
                    "en": "He enjoys being praised.",
                    "ua": "Lubi być chwalony."
                }
            ]
        },
        {
            "label": "Po przyimkach",
            "color": "blue",
            "description": "Po <strong>bez, po, przed, pomimo</strong>:",
            "examples": [
                {
                    "en": "He left without being noticed.",
                    "ua": "Wyszedł niezauważony."
                },
                {
                    "en": "After being rejected, she tried again.",
                    "ua": "Po odrzuceniu próbowała ponownie."
                },
                {
                    "en": "Despite being warned, he continued.",
                    "ua": "Pomimo ostrzeżenia kontynuował."
                }
            ]
        }
    ]
}

{
    "title": "5. Bierny gerund perfect",
    "sections": [
        {
            "label": "Wcześniejsza czynność",
            "color": "emerald",
            "description": "Użyj tej formy, gdy jedna czynność <strong>wydarzyła się przed drugą</strong>:",
            "examples": [
                {
                    "en": "Having been warned, he was more careful.",
                    "ua": "Otrzymawszy ostrzeżenie, był bardziej ostrożny."
                },
                {
                    "en": "Having been told the truth, she felt relieved.",
                    "ua": "Gdy poznała prawdę, poczuła ulgę."
                }
            ]
        },
        {
            "label": "Styl formalny",
            "color": "blue",
            "description": "Często w <strong>naukowym i oficjalnym</strong> piśmie:",
            "examples": [
                {
                    "en": "Having been approved, the project will begin.",
                    "ua": "Po akceptacji projekt zostanie rozpoczęty."
                },
                {
                    "en": "Having been elected, she took office.",
                    "ua": "Po wyborach objęła urząd."
                }
            ]
        }
    ]
}

{
    "title": "6. Tabela zbiorcza form",
    "intro": "Wszystkie formy bierne bezokolicznika i gerunda:",
    "rows": [
        {
            "en": "to be + V3",
            "ua": "Bezokolicznik bierny",
            "note": "The work needs to be done."
        },
        {
            "en": "to have been + V3",
            "ua": "Bezokolicznik bierny perfect",
            "note": "He seems to have been promoted."
        },
        {
            "en": "being + V3",
            "ua": "Bierny gerund",
            "note": "She hates being interrupted."
        },
        {
            "en": "having been + V3",
            "ua": "Bierny gerund perfect",
            "note": "Having been warned, he left."
        }
    ],
    "warning": "📌 Formy perfect pokazują czynność, która wydarzyła się wcześniej niż inna!"
}
